private async renderToHTMLImpl(
  req: ServerRequest,
  res: ServerResponse,
  pathname: string,
  query: ParsedUrlQuery = {}
): Promise<string | null> {
  return this.getStaticHTML((ctx) => this.renderToResponse(ctx), {
    req,
    res,
    pathname,
    query,
  })
}

